Here's how to write modern MSTest tests for your `DataFetcher` class:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;
    private readonly MockHttpMessageHandler _handler;
    private readonly DataFetcher _fetcher;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
        _handler = new MockHttpMessageHandler();
        var client = new HttpClient(_handler) { BaseAddress = new Uri("https://example.com") };
        _fetcher = new DataFetcher(client);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessfulResponse_ReturnsContent()
    {
        // Arrange
        _handler.ResponseContent = "hello world";
        _handler.StatusCode = HttpStatusCode.OK;

        // Act
        var result = await _fetcher.FetchAsync("https://example.com/data", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFoundResponse_ThrowsHttpRequestException()
    {
        // Arrange
        _handler.StatusCode = HttpStatusCode.NotFound;

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await _fetcher.FetchAsync("https://example.com/missing", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange
        _handler.SimulateDelay = TimeSpan.FromSeconds(10);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // Cancel immediately

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await _fetcher.FetchAsync("https://example.com/slow", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_TimeoutViaTestContext_IsCancelledGracefully()
    {
        // Arrange - use TestContext.CancellationToken which fires on [Timeout]
        _handler.SimulateDelay = TimeSpan.FromSeconds(30);

        // Act & Assert - the [Timeout] attribute triggers cancellation via TestContext
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await _fetcher.FetchAsync("https://example.com/timeout", _testContext.CancellationToken));
    }

    // Simple test double for HttpMessageHandler
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        public HttpStatusCode StatusCode { get; set; } = HttpStatusCode.OK;
        public string ResponseContent { get; set; } = string.Empty;
        public TimeSpan SimulateDelay { get; set; } = TimeSpan.Zero;

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (SimulateDelay > TimeSpan.Zero)
            {
                await Task.Delay(SimulateDelay, cancellationToken);
            }

            return new HttpResponseMessage(StatusCode)
            {
                Content = new StringContent(ResponseContent)
            };
        }
    }
}
```

**Key patterns demonstrated:**

1. **`TestContext` via constructor injection** (MSTest 3.6+) — enables `readonly` fields
2. **`[Timeout(ms)]` + `_testContext.CancellationToken`** — the timeout fires the token automatically, so your async code gets cancelled cleanly
3. **`Assert.ThrowsExactlyAsync<T>`** — modern exception testing (no `[ExpectedException]`)
4. **Sealed test class** — best practice for performance/design clarity
5. **Cancellation token forwarding** — tests verify your code actually respects the token

The `[Timeout]` attribute and `TestContext.CancellationToken` work together: when the timeout expires, the token is cancelled, which propagates through your `async` call chain. This is the idiomatic way to test timeout behavior in MSTest 3.x+.
